import java.util.*;

public class LRUCacheHitCount {
    static int cacheSize;
    static LinkedHashMap<String, Integer> cache;

    public static int[] solution(int cacheSize, String[] cities) {
        int totalTime = 0, hits = 0;
        cache = new LinkedHashMap<String, Integer>(cacheSize, 0.75f, true) {
            @Override
            protected boolean removeEldestEntry(Map.Entry<String, Integer> eldest) {
                return size() > cacheSize;
            }
        };

        for (String city : cities) {
            String key = city.toLowerCase();
            if (cache.containsKey(key)) {
                cache.get(key); // access order 갱신
                totalTime += 1;
                hits++;
            } else {
                cache.put(key, 1);
                totalTime += 5;
            }
        }
        return new int[]{totalTime, hits};
    }

    public static void main(String[] args) {
        int[] result = solution(3, new String[]{"Jeju","Pangyo","Seoul","Jeju","Pangyo","Seoul","Jeju"});
        System.out.println("totalTime=" + result[0] + ", hits=" + result[1]);
    }
}

