public class FileNameSort {
    public static String[] solution(String[] files) {
        Pattern p = Pattern.compile("([^0-9]+)([0-9]{1,5})(.*)");
        Arrays.sort(files, (a, b) -> {
            Matcher ma = p.matcher(a);
            Matcher mb = p.matcher(b);
            ma.find(); mb.find();
            int headCmp = ma.group(1).toLowerCase().compareTo(mb.group(1).toLowerCase());
            if (headCmp != 0) return headCmp;
            return Integer.parseInt(ma.group(2)) - Integer.parseInt(mb.group(2));
        });
        return files;
    }

    public static void main(String[] args) {
        String[] result = solution(new String[]{"img12.png","img10.png","img02.png","img1.png","IMG01.PNG","img2.PNG"});
        System.out.println(Arrays.toString(result));
    }
}

