public class TupleParsing {
    public static int[] solution(String s) {
        // 외부 {{ }} 제거 후 내부 집합 추출
        s = s.substring(2, s.length() - 2); // 앞뒤 {{ 제거
        String[] sets = s.split("\\},\\{");
        // 원소 수 기준 정렬
        Arrays.sort(sets, Comparator.comparingInt(a -> a.split(",").length));

        List<Integer> result = new ArrayList<>();
        Set<Integer> seen = new HashSet<>();
        for (String set : sets) {
            for (String num : set.split(",")) {
                int n = Integer.parseInt(num.trim());
                if (seen.add(n)) result.add(n);
            }
        }
        return result.stream().mapToInt(Integer::intValue).toArray();
    }

    public static void main(String[] args) {
        System.out.println(Arrays.toString(solution("{{2},{2,1},{2,1,3},{2,1,3,4}}")));
    }
}

