public class Friends4Block {
    public static int solution(int m, int n, String[] board) {
        char[][] grid = new char[m][n];
        for (int i = 0; i < m; i++) grid[i] = board[i].toCharArray();

        int total = 0;
        while (true) {
            boolean[][] toRemove = new boolean[m][n];
            for (int r = 0; r < m - 1; r++) {
                for (int c = 0; c < n - 1; c++) {
                    char ch = grid[r][c];
                    if (ch != '.' && ch == grid[r][c+1] && ch == grid[r+1][c] && ch == grid[r+1][c+1]) {
                        toRemove[r][c] = toRemove[r][c+1] = toRemove[r+1][c] = toRemove[r+1][c+1] = true;
                    }
                }
            }
            int count = 0;
            for (int r = 0; r < m; r++)
                for (int c = 0; c < n; c++)
                    if (toRemove[r][c]) { grid[r][c] = '.'; count++; }
            if (count == 0) break;
            total += count;
            // 중력: 각 열에서 아래부터 채우기
            for (int c = 0; c < n; c++) {
                int bottom = m - 1;
                for (int r = m - 1; r >= 0; r--) {
                    if (grid[r][c] != '.') grid[bottom--][c] = grid[r][c];
                }
                while (bottom >= 0) grid[bottom--][c] = '.';
            }
        }
        return total;
    }

    public static void main(String[] args) {
        System.out.println(solution(4, 5, new String[]{"CCBDE","AAADE","AAABF","CCBBF"}));
    }
}

