public class LIS {
    public static int lisLength(int[] nums) {
        int n = nums.length;
        int[] tails = new int[n];
        int size = 0;
        for (int num : nums) {
            int lo = 0, hi = size;
            while (lo < hi) {
                int mid = (lo + hi) / 2;
                if (tails[mid] < num) lo = mid + 1;
                else hi = mid;
            }
            tails[lo] = num;
            if (lo == size) size++;
        }
        return size;
    }

    public static List<Integer> lisSequence(int[] nums) {
        int n = nums.length;
        int[] tails = new int[n];
        int[] tailIdx = new int[n]; // tails 위치별 원소의 실제 인덱스
        int[] parent = new int[n];
        Arrays.fill(parent, -1);
        int size = 0;

        for (int i = 0; i < n; i++) {
            int lo = 0, hi = size;
            while (lo < hi) {
                int mid = (lo + hi) / 2;
                if (nums[tailIdx[mid]] < nums[i]) lo = mid + 1;
                else hi = mid;
            }
            tails[lo] = nums[i];
            tailIdx[lo] = i;
            if (lo > 0) parent[i] = tailIdx[lo - 1];
            if (lo == size) size++;
        }

        LinkedList<Integer> seq = new LinkedList<>();
        int idx = tailIdx[size - 1];
        while (idx != -1) {
            seq.addFirst(nums[idx]);
            idx = parent[idx];
        }
        return seq;
    }

    public static void main(String[] args) {
        int[] nums = {10, 9, 2, 5, 3, 7, 101, 18};
        System.out.println("Length: " + lisLength(nums));
        System.out.println("Sequence: " + lisSequence(nums));
    }
}

public class EditDistance {
    public static int minDistance(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[][] dp = new int[m + 1][n + 1];
        for (int i = 0; i <= m; i++) dp[i][0] = i;
        for (int j = 0; j <= n; j++) dp[0][j] = j;

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (word1.charAt(i - 1) == word2.charAt(j - 1)) {
                    dp[i][j] = dp[i - 1][j - 1];
                } else {
                    dp[i][j] = 1 + Math.min(dp[i - 1][j - 1],
                                   Math.min(dp[i - 1][j], dp[i][j - 1]));
                }
            }
        }
        return dp[m][n];
    }

    public static void main(String[] args) {
        System.out.println(minDistance("horse", "ros")); // 3
        System.out.println(minDistance("intention", "execution")); // 5
    }
}

