public class DeliveryStats {
    public static double[] computeStats(int[][] logs) {
        int n = logs.length;
        long[] times = new long[n];
        long sum = 0;
        for (int i = 0; i < n; i++) {
            times[i] = logs[i][2] - logs[i][1];
            sum += times[i];
        }
        Arrays.sort(times);

        double avg = (double) sum / n;
        double median = (n % 2 == 1) ? times[n / 2] : (times[n/2-1] + times[n/2]) / 2.0;
        int p99Idx = (int) Math.ceil(n * 0.99) - 1;
        p99Idx = Math.min(p99Idx, n - 1);
        double p99 = times[p99Idx];

        return new double[]{avg, median, p99};
    }

    public static void main(String[] args) {
        int[][] logs = {{1,0,5},{2,1,9},{3,2,4},{4,3,7},{5,4,6}};
        double[] stats = computeStats(logs);
        System.out.printf("avg=%.1f, median=%.1f, p99=%.1f%n", stats[0], stats[1], stats[2]);
    }
}

