public class InventoryManager {
    private final Map<String, Integer> stockMap = new HashMap<>();
    private final PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
    private final Map<String, Integer> idxMap = new HashMap<>(); // id→현재재고 (pq sync용)

    public void addItem(String id, int stock) {
        stockMap.put(id, stock);
        pq.offer(new int[]{stock, id.hashCode()});
        idxMap.put(id, stock);
    }

    public void decreaseStock(String id, int amount) {
        int cur = stockMap.getOrDefault(id, 0) - amount;
        if (cur <= 0) {
            stockMap.remove(id);
            idxMap.remove(id);
        } else {
            stockMap.put(id, cur);
            idxMap.put(id, cur);
            pq.offer(new int[]{cur, id.hashCode()});
        }
    }

    // 단순화된 버전: PQ는 참고용, 실제 최소는 stockMap에서
    public Map.Entry<String, Integer> getMinStock() {
        return stockMap.entrySet().stream()
            .min(Map.Entry.comparingByValue())
            .orElse(null);
    }

    // O(log N) 버전: lazy deletion PQ 사용
    private final PriorityQueue<long[]> lazyPq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
    private final Map<String, Long> versionMap = new HashMap<>();
    private long version = 0;

    public void addItemFast(String id, int stock) {
        stockMap.put(id, stock);
        long v = ++version;
        versionMap.put(id, v);
        lazyPq.offer(new long[]{stock, v});
    }

    public int getMinStockFast() {
        while (!lazyPq.isEmpty()) {
            long[] top = lazyPq.peek();
            // 버전이 최신이면 유효한 항목
            if (versionMap.containsValue(top[1])) return (int) top[0];
            lazyPq.poll();
        }
        return -1;
    }

    public static void main(String[] args) {
        InventoryManager mgr = new InventoryManager();
        mgr.addItem("A", 10);
        mgr.addItem("B", 5);
        mgr.decreaseStock("A", 3);
        System.out.println(mgr.getMinStock());
    }
}

public class SlidingWindowLog {
    public static long maxRequests(int[][] logs, int W) {
        // 타임스탬프 기준 정렬 가정 (이미 정렬됨)
        long windowSum = 0, maxSum = 0;
        int left = 0;
        for (int right = 0; right < logs.length; right++) {
            windowSum += logs[right][1];
            // 윈도우 시작 조건: logs[right][0] - logs[left][0] >= W
            while (logs[right][0] - logs[left][0] >= W) {
                windowSum -= logs[left][1];
                left++;
            }
            maxSum = Math.max(maxSum, windowSum);
        }
        return maxSum;
    }

    public static void main(String[] args) {
        int[][] logs = {{1,3},{2,5},{4,2},{7,4},{8,1}};
        System.out.println(maxRequests(logs, 3)); // 8 (t=1~3: 3+5=8)
    }
}

