public class PriceHistory {
    public static int[] stockSpan(int[] prices) {
        int n = prices.length;
        int[] result = new int[n];
        Deque<Integer> stack = new ArrayDeque<>();

        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty() && prices[stack.peek()] >= prices[i]) {
                int idx = stack.pop();
                result[idx] = i - idx;
            }
            stack.push(i);
        }
        // 스택에 남은 인덱스들: 끝까지 낮아지지 않음
        while (!stack.isEmpty()) {
            int idx = stack.pop();
            result[idx] = n - idx;
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println(Arrays.toString(stockSpan(new int[]{1, 2, 3, 0, 2})));
    }
}

