public class RecommendationScore {
    static final Map<String, Integer> ACTION_SCORE = Map.of("view", 1, "click", 3, "purchase", 10);

    public static List<String[]> topK(String[][] logs, int k) {
        Map<String, Integer> scoreMap = new HashMap<>();
        for (String[] log : logs) {
            String item = log[1], action = log[2];
            scoreMap.merge(item, ACTION_SCORE.getOrDefault(action, 0), Integer::sum);
        }

        // MinHeap 크기 K 유지
        PriorityQueue<Map.Entry<String, Integer>> pq =
            new PriorityQueue<>(Comparator.comparingInt(Map.Entry::getValue));
        for (Map.Entry<String, Integer> e : scoreMap.entrySet()) {
            pq.offer(e);
            if (pq.size() > k) pq.poll();
        }

        List<String[]> result = new ArrayList<>();
        while (!pq.isEmpty()) result.add(0, new String[]{pq.poll().getKey(), String.valueOf(pq.peek() != null ? 0 : 0)});
        // 실제 점수 포함 버전
        result.clear();
        List<Map.Entry<String, Integer>> topList = new ArrayList<>(pq);
        // 재구성
        PriorityQueue<Map.Entry<String, Integer>> pq2 =
            new PriorityQueue<>((a, b) -> b.getValue() - a.getValue());
        pq2.addAll(scoreMap.entrySet());
        for (int i = 0; i < k && !pq2.isEmpty(); i++) {
            Map.Entry<String, Integer> e = pq2.poll();
            result.add(new String[]{e.getKey(), String.valueOf(e.getValue())});
        }
        return result;
    }

    public static void main(String[] args) {
        String[][] logs = {{"u1","A","view"},{"u1","A","click"},{"u2","A","purchase"},{"u2","B","view"}};
        System.out.println(topK(logs, 1));
    }
}

