public class DeadlockDetection {
    static final int WHITE = 0, GRAY = 1, BLACK = 2;
    static Map<String, List<String>> graph;
    static Map<String, Integer> color;
    static Map<String, String> parent;
    static List<String> cycleNodes;

    public static List<String> detectDeadlock(String[][] transactions) {
        graph = new HashMap<>();
        color = new HashMap<>();
        parent = new HashMap<>();
        cycleNodes = new ArrayList<>();

        Set<String> accounts = new HashSet<>();
        for (String[] t : transactions) {
            accounts.add(t[0]); accounts.add(t[1]);
            graph.computeIfAbsent(t[0], k -> new ArrayList<>()).add(t[1]);
        }
        accounts.forEach(a -> { graph.putIfAbsent(a, new ArrayList<>()); color.put(a, WHITE); });

        for (String acc : accounts) {
            if (color.get(acc) == WHITE) dfs(acc, null);
        }
        return cycleNodes;
    }

    static boolean dfs(String u, String par) {
        color.put(u, GRAY);
        parent.put(u, par);
        for (String v : graph.get(u)) {
            if (color.get(v) == GRAY) {
                // 사이클 복원
                String cur = u;
                while (!cur.equals(v)) {
                    cycleNodes.add(cur);
                    cur = parent.get(cur);
                }
                cycleNodes.add(v);
                return true;
            }
            if (color.get(v) == WHITE) dfs(v, u);
        }
        color.put(u, BLACK);
        return false;
    }

    public static void main(String[] args) {
        System.out.println(detectDeadlock(new String[][]{{"A","B"},{"B","C"},{"C","A"},{"D","E"}}));
    }
}

