public class EventSort {
    static final Map<String, Integer> TYPE_PRIORITY = Map.of("DEPOSIT", 1, "WITHDRAW", 2, "TRANSFER", 3);

    static class Event {
        String userId, eventType;
        long timestamp, amount;
        Event(String u, String t, long ts, long a) { userId=u; eventType=t; timestamp=ts; amount=a; }
