    }

    public static List<Event> sortEvents(List<Event> events) {
        events.sort(Comparator
            .comparingLong((Event e) -> e.timestamp)
            .thenComparingInt(e -> TYPE_PRIORITY.getOrDefault(e.eventType, 99))
            .thenComparingLong((Event e) -> -e.amount));
        return events;
    }

    public static void main(String[] args) {
        List<Event> events = new ArrayList<>(Arrays.asList(
            new Event("A","WITHDRAW",100,500),
            new Event("B","DEPOSIT",100,200),
            new Event("C","TRANSFER",100,1000),
            new Event("D","DEPOSIT",99,100)
        ));
        sortEvents(events).forEach(System.out::println);
    }
}

import java.util.*;

public class BalanceRollback {
    public static long simulate(long initialBalance, String[] commands) {
        Deque<Long> commitStack = new ArrayDeque<>();
        commitStack.push(initialBalance);
        long current = initialBalance;

        for (String cmd : commands) {
            if (cmd.startsWith("DEPOSIT")) {
                current += Long.parseLong(cmd.split(" ")[1]);
            } else if (cmd.startsWith("WITHDRAW")) {
                long amount = Long.parseLong(cmd.split(" ")[1]);
                if (current < amount) throw new IllegalStateException("잔액 부족");
                current -= amount;
            } else if (cmd.equals("COMMIT")) {
                commitStack.push(current);
            } else if (cmd.equals("ROLLBACK")) {
                if (commitStack.size() > 1) current = commitStack.peek();
                // 초기 커밋은 유지
            }
        }
        return current;
    }

    public static void main(String[] args) {
        System.out.println(simulate(1000, new String[]{"DEPOSIT 500","WITHDRAW 200","ROLLBACK","DEPOSIT 100","COMMIT"}));
    }
}

