public class FeeCalculation {
    public static BigDecimal totalFee(String[] amounts, String feeRate) {
        BigDecimal rate = new BigDecimal(feeRate);
        BigDecimal total = BigDecimal.ZERO;

        for (String amount : amounts) {
            BigDecimal a = new BigDecimal(amount);
            BigDecimal fee = a.multiply(rate).setScale(2, RoundingMode.HALF_UP);
            total = total.add(fee);
        }
        return total;
    }

    public static void main(String[] args) {
        String[] amounts = {"1000.50", "2500.75", "999.99"};
        System.out.println(totalFee(amounts, "0.015")); // 정밀 계산

