public class FraudDetection {
    public static List<Integer> findPattern(String[] stream, String[] pattern) {
        int n = stream.length, m = pattern.length;
        int[] fail = computeFailure(pattern);
        List<Integer> result = new ArrayList<>();

        int j = 0;
        for (int i = 0; i < n; i++) {
            while (j > 0 && !stream[i].equals(pattern[j])) j = fail[j - 1];
            if (stream[i].equals(pattern[j])) j++;
            if (j == m) {
                result.add(i - m + 1);
                j = fail[j - 1];
            }
        }
        return result;
    }

    static int[] computeFailure(String[] pattern) {
        int m = pattern.length;
        int[] fail = new int[m];
        int k = 0;
        for (int i = 1; i < m; i++) {
            while (k > 0 && !pattern[i].equals(pattern[k])) k = fail[k - 1];
            if (pattern[i].equals(pattern[k])) k++;
            fail[i] = k;
        }
        return fail;
    }

    public static void main(String[] args) {
        System.out.println(findPattern(
            new String[]{"W","D","W","W","D","W","D"},
            new String[]{"W","D"}));
    }
}

import java.util.*;

public class DeliveryRoute {
    static double dist(int[] a, int[] b) {
        double dx = a[0] - b[0], dy = a[1] - b[1];
        return Math.sqrt(dx * dx + dy * dy);
    }

    public static List<int[]> nearestNeighbor(int[] start, int[][] dests) {
        int n = dests.length;
        boolean[] visited = new boolean[n];
        List<int[]> route = new ArrayList<>();
        int[] cur = start;
        double totalDist = 0;

        for (int step = 0; step < n; step++) {
            int nearest = -1;
            double minDist = Double.MAX_VALUE;
            for (int i = 0; i < n; i++) {
                if (!visited[i]) {
                    double d = dist(cur, dests[i]);
                    if (d < minDist) { minDist = d; nearest = i; }
                }
            }
            visited[nearest] = true;
            route.add(dests[nearest]);
            totalDist += minDist;
            cur = dests[nearest];
        }
        System.out.printf("Total distance: %.2f%n", totalDist);
        return route;
    }

    public static void main(String[] args) {
        int[][] dests = {{1,2},{3,1},{5,4},{2,3}};
        List<int[]> route = nearestNeighbor(new int[]{0,0}, dests);
        route.forEach(p -> System.out.println(Arrays.toString(p)));
    }
}

import java.util.*;
import java.util.stream.*;

public class GeoTimeMatching {
    static final double EARTH_RADIUS_KM = 6371.0;

    static double haversine(double lat1, double lng1, double lat2, double lng2) {
        double dLat = Math.toRadians(lat2 - lat1);
        double dLng = Math.toRadians(lng2 - lng1);
        double a = Math.sin(dLat/2)*Math.sin(dLat/2)
                 + Math.cos(Math.toRadians(lat1))*Math.cos(Math.toRadians(lat2))
                 * Math.sin(dLng/2)*Math.sin(dLng/2);
        return EARTH_RADIUS_KM * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    }

    static class Post {
        double lat, lng;
        long timestamp;
        Post(double lat, double lng, long ts) { this.lat=lat; this.lng=lng; this.timestamp=ts; }
    }

    public static List<Post> findNearbyRecent(double uLat, double uLng, double rKm, long tMs, List<Post> posts) {
        long now = System.currentTimeMillis();
        return posts.stream()
            .filter(p -> (now - p.timestamp) <= tMs)
            .filter(p -> haversine(uLat, uLng, p.lat, p.lng) <= rKm)
            .sorted(Comparator.comparingLong((Post p) -> p.timestamp).reversed())
            .collect(Collectors.toList());
    }

    public static void main(String[] args) {
        long now = System.currentTimeMillis();
        List<Post> posts = Arrays.asList(
            new Post(37.51, 127.01, now - 2*3600*1000L),
            new Post(37.6, 127.0, now - 1*3600*1000L),
            new Post(37.5, 127.0, now - 30*3600*1000L)
        );
        findNearbyRecent(37.5, 127.0, 2.0, 24*3600*1000L, posts)
            .forEach(p -> System.out.println(p.lat + "," + p.lng));
    }
}

import java.util.*;

public class OrderStateMachine {
    enum OrderState {
        PENDING(Set.of("CONFIRM", "CANCEL")),
        CONFIRMED(Set.of("SHIP", "CANCEL")),
        SHIPPING(Set.of("DELIVER")),
        DELIVERED(Set.of()),
        CANCELLED(Set.of());

        final Set<String> allowedEvents;
        OrderState(Set<String> events) { this.allowedEvents = events; }

        OrderState transition(String event) {
            if (!allowedEvents.contains(event))
                throw new IllegalStateException(this + " 상태에서 " + event + " 불가");
            return switch (event) {
                case "CONFIRM" -> CONFIRMED;
                case "SHIP" -> SHIPPING;
                case "DELIVER" -> DELIVERED;
                case "CANCEL" -> CANCELLED;
                default -> throw new IllegalArgumentException("Unknown event: " + event);
            };
        }
    }

    public static OrderState processEvents(String[] events) {
        OrderState state = OrderState.PENDING;
        for (String event : events) {
            state = state.transition(event);
        }
        return state;
    }

    public static void main(String[] args) {
        System.out.println(processEvents(new String[]{"CONFIRM", "SHIP", "DELIVER"}));
        try {
            processEvents(new String[]{"CONFIRM", "DELIVER"}); // CONFIRMED에서 DELIVER 불가
        } catch (IllegalStateException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}

import java.util.*;

public class WeightedRandom {
    private final String[] ads;
    private final int[] prefixWeights;
    private final int total;
    private final Random rand = new Random();

    public WeightedRandom(String[] ads, int[] weights) {
        this.ads = ads;
        prefixWeights = new int[weights.length];
        prefixWeights[0] = weights[0];
        for (int i = 1; i < weights.length; i++)
            prefixWeights[i] = prefixWeights[i-1] + weights[i];
        total = prefixWeights[prefixWeights.length - 1];
    }

    public String pickAd() {
        int target = rand.nextInt(total); // [0, total)
        int lo = 0, hi = prefixWeights.length - 1;
        while (lo < hi) {
            int mid = (lo + hi) / 2;
            if (prefixWeights[mid] <= target) lo = mid + 1;
            else hi = mid;
        }
        return ads[lo];
    }

    public static void main(String[] args) {
        WeightedRandom wr = new WeightedRandom(
            new String[]{"A","B","C"}, new int[]{1,3,6});
        Map<String, Integer> cnt = new HashMap<>();
        for (int i = 0; i < 10000; i++)
            cnt.merge(wr.pickAd(), 1, Integer::sum);
        System.out.println(cnt); // 약 A:1000, B:3000, C:6000
    }
}

public class TokenBucketRateLimit {
    private long tokens;
    private long lastRefillTime;
    private final long capacity;
    private final long refillRate; // 초당 토큰

    public TokenBucketRateLimit(long capacity, long refillRate) {
        this.capacity = capacity;
        this.refillRate = refillRate;
        this.tokens = capacity; // 초기 만충
        this.lastRefillTime = 0;
    }

    public long[] processBatch(long[][] requests) {
        long totalSent = 0, totalDropped = 0;
        for (long[] req : requests) {
            long timestamp = req[0], count = req[1];
            refill(timestamp);
            long sendable = Math.min(tokens, count);
            tokens -= sendable;
            totalSent += sendable;
            totalDropped += count - sendable;
        }
        return new long[]{totalSent, totalDropped};
    }

    private void refill(long now) {
        long elapsed = now - lastRefillTime;
        long added = elapsed * refillRate;
        tokens = Math.min(tokens + added, capacity);
        lastRefillTime = now;
    }

    public static void main(String[] args) {
        TokenBucketRateLimit tb = new TokenBucketRateLimit(10, 2);
        long[] result = tb.processBatch(new long[][]{{0,5},{1,8},{3,3}});
        System.out.println("sent=" + result[0] + ", dropped=" + result[1]);
    }
}
